import{_ as p,X as o,Y as c,$ as n,a0 as a,a1 as s,a2 as i,a3 as u,F as e}from"./framework-abbf9d44.js";const r="/assets/2024-03-25-14-32-16-4b6185d1.png",d="/assets/2024-03-25-18-17-02-f2efd64b.png",k={},m=n("h1",{id:"",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#","aria-hidden":"true"},"#")],-1),_=n("code",null,"relabel_configs",-1),b=u('<h2 id="replace-laabelmap" tabindex="-1"><a class="header-anchor" href="#replace-laabelmap" aria-hidden="true">#</a> replace&amp;laabelmap</h2><p>在Prometheus所有的Target实例中，都包含一些默认的Metadata标签信息。可以通过Prometheus UI的Targets页面中查看这些实例的Metadata标签的内容：</p><p>在Prometheus的所有的实例中，都包含了一些默认的元数据(Metadata)标签，如下图</p><figure><img src="'+r+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>如： <code>__address__</code> ：当前Target实例的访问地址<code>&lt;host&gt;:&lt;port&gt;</code> , 通常来说，Target以<code>__</code>作为前置的标签是在系统内部使用的,有点像PY的私有方法，因此这些标签不会被写入到样本数据中，如果需要，可通过<code>scrape_configs</code>进行操作</p><h3 id="replace" tabindex="-1"><a class="header-anchor" href="#replace" aria-hidden="true">#</a> replace</h3><p>一个简单的例子</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">scrape_configs</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">job_name</span><span class="token punctuation">:</span> test
    <span class="token key atrule">kubernetes_sd_configs</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">role</span><span class="token punctuation">:</span> pod
      <span class="token key atrule">api_server</span><span class="token punctuation">:</span> http<span class="token punctuation">:</span>//xxxx.xx.xx<span class="token punctuation">:</span>xxxx
      <span class="token key atrule">tls_config</span><span class="token punctuation">:</span>
        <span class="token key atrule">insecure_skip_verify</span><span class="token punctuation">:</span> <span class="token boolean important">true</span>
    <span class="token key atrule">relabel_configs</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">source_labels</span><span class="token punctuation">:</span>  <span class="token punctuation">[</span><span class="token string">&quot;__address__&quot;</span><span class="token punctuation">]</span>
      <span class="token key atrule">target_label</span><span class="token punctuation">:</span> <span class="token string">&quot;address&quot;</span>
      <span class="token comment">#action: replace  # 这个是默认的行为，如果未指定action，则为replace</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将 <code>source_labels</code> 下 <code>__address__</code> 的值，赋值到标签为 <code>addr</code> 下。</p><p>除了使用<code>replace</code>以外，还可以指定<code>action</code>为<code>labelmap</code>，labelmap会根据<code>regex</code>的定义去匹配所有实例标签名称，并且以匹配到的内容为新的标签名，其值作为新标签的值</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">job_name</span><span class="token punctuation">:</span> <span class="token string">&#39;kubernetes-nodes&#39;</span>
  <span class="token key atrule">kubernetes_sd_configs</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">role</span><span class="token punctuation">:</span> node
  <span class="token key atrule">relabel_configs</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">action</span><span class="token punctuation">:</span> labelmap
    <span class="token key atrule">regex</span><span class="token punctuation">:</span> __meta_kubernetes_node_label_(.+)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>还可以使用<code>labelkeep</code>和<code>keepdrop</code>对标签进行过滤，是丢弃还是保留。</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">relabel_configs</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">regex</span><span class="token punctuation">:</span> label_should_drop_(.+)
    <span class="token key atrule">action</span><span class="token punctuation">:</span> labeldrop
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>总结： 通过Relabeling机制，可以对prometheus实例的标签进行规范的管理与维护。有了标签的规范，后续就可按标签做很多事情</p><h3 id="keep-drop" tabindex="-1"><a class="header-anchor" href="#keep-drop" aria-hidden="true">#</a> keep/drop</h3><p>标签虽有了管理，但如果是通过配置中心或集群发现等，自动发现服务，server端若不做控制，将会发现所有的实例，这一点是我们不想看到的。比如我们在集群中加了个测试节点，或者有多个server，做业务区分等。此时可通过keep/drop行为，来做过滤。</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">scrape_configs</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">job_name</span><span class="token punctuation">:</span> test
    <span class="token key atrule">kubernetes_sd_configs</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">role</span><span class="token punctuation">:</span> pod
      <span class="token key atrule">api_server</span><span class="token punctuation">:</span> http<span class="token punctuation">:</span>//xxxx.xx.xx<span class="token punctuation">:</span>xxxx
      <span class="token key atrule">tls_config</span><span class="token punctuation">:</span>
        <span class="token key atrule">insecure_skip_verify</span><span class="token punctuation">:</span> <span class="token boolean important">true</span>
    <span class="token key atrule">relabel_configs</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">source_labels</span><span class="token punctuation">:</span>  <span class="token punctuation">[</span><span class="token string">&quot;__address__&quot;</span><span class="token punctuation">]</span>
      <span class="token key atrule">regex</span><span class="token punctuation">:</span> <span class="token string">&quot;192.168.2.133:10249&quot;</span>
      <span class="token key atrule">action</span><span class="token punctuation">:</span> keep
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>action设置为keep，会根据regex匹配后进行保留。若为drop则为丢弃</strong></p><h3 id="hashmod" tabindex="-1"><a class="header-anchor" href="#hashmod" aria-hidden="true">#</a> hashmod</h3><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">scrape_configs</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">job_name</span><span class="token punctuation">:</span> <span class="token string">&#39;test&#39;</span>
    <span class="token key atrule">relabel_configs</span><span class="token punctuation">:</span>
        <span class="token punctuation">-</span> <span class="token key atrule">source_labels</span><span class="token punctuation">:</span> <span class="token punctuation">[</span>__address__<span class="token punctuation">]</span>
        <span class="token key atrule">modulus</span><span class="token punctuation">:</span>       <span class="token number">4</span>
        <span class="token key atrule">target_label</span><span class="token punctuation">:</span>  tmp_hash
        <span class="token key atrule">action</span><span class="token punctuation">:</span>        hashmod
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,20),v={href:"https://github.com/prometheus/prometheus/blob/main/model/relabel/relabel.go#L289",target:"_blank",rel:"noopener noreferrer"},g=n("p",null,"根据当前Target实例__address__的值以4作为系数，这样每个Target实例都会包含一个新的标签tmp_hash，并且该值的范围在1~4之间，查看Target实例的标签信息，可以看到如下的结果，每一个Target实例都包含了一个新的tmp_hash值",-1),h=n("figure",null,[n("img",{src:d,alt:"",tabindex:"0",loading:"lazy"}),n("figcaption")],-1);function y(x,f){const t=e("RouterLink"),l=e("ExternalLinkIcon");return o(),c("div",null,[m,n("p",null,[a("在"),s(t,{to:"/ops/monitor/prometheus/05-exporter.html"},{default:i(()=>[a("exporter")]),_:1}),a("的配置与集成环节，接触了文件的引入(动态服务发现方法之一)和"),_,a("，看的一脸懵逼，所以去详细看了下，并记录一下。")]),b,n("p",null,[n("a",v,[a("https://github.com/prometheus/prometheus/blob/main/model/relabel/relabel.go#L289"),s(l)])]),g,h])}const q=p(k,[["render",y],["__file","06-relabel.html.vue"]]);export{q as default};
